mapper.select:
SELECT P.PRODUCT_ID , P.STORE_ID , P.CATEGORY_ID , P.PARTNER_ID , P.STATUS , P.PRODUCT_NM , P.P_PRODUCT_CD /* 계열사 상품 코드 */ , P.P_VARCODE_NO /* 계열사 상품 코드 88코드 */ , P.STATUS , MAX(P.ORG_PRICE) ORG_PRICE /* 소비자가 */ , MAX(P.ORG_SALES_PRICE) ORG_SALES_PRICE /* 현장가 */ , P.DESCRIPTION , IFNULL(SUM(D.BOX_QTY), 0) AS BOX_QTY , IFNULL(SUM(D.ORG_STOCK_QTY), 0) - IFNULL(SUM(SD.QTY),0) AS CUR_STOCK_QTY , IFNULL(SUM(D.ORG_STOCK_QTY), 0) AS ORG_STOCK_QTY , C.CATEGORY_NM AS CATEGORY_NM , S.PARTNER_NM AS PARTNER_NM , DATE_FORMAT(MIN(D.RECEIVED_DATE), '%Y-%m-%d') AS FIRST_RECEIVED_DATE , DATE_FORMAT(MAX(D.RECEIVED_DATE), '%Y-%m-%d') AS LAST_RECEIVED_DATE , 'N' EDITOR , (SELECT MAX(NAME) NAME FROM user_mst WHERE USER_ID = (CASE WHEN P.UPDATE_USER IS NOT NULL THEN P.UPDATE_USER ELSE P.CREATE_USER END) ) UPDATE_USER , CASE WHEN P.UPDATE_DATE IS NOT NULL THEN DATE_FORMAT(P.UPDATE_DATE, '%Y-%m-%d %H:%i:%S') ELSE DATE_FORMAT(P.CREATE_DATE, '%Y-%m-%d %H:%i:%S') END UPDATE_DATE FROM product_mst P LEFT JOIN product_dtl D ON P.PRODUCT_ID = D.PRODUCT_ID LEFT JOIN category_mst C ON P.CATEGORY_ID = C.CATEGORY_ID LEFT JOIN store_partner_mst S ON P.PARTNER_ID = S.PARTNER_ID LEFT JOIN ( SELECT SM.STORE_ID ,SD.PRODUCT_DTL_ID , SD.PRODUCT_ID , sum( SD.QTY) QTY FROM sales_mst SM JOIN sales_dtl SD ON SM.SALES_ID = SD.SALES_ID WHERE SM.SALES_STATUS = 'COMPLETE' GROUP BY SM.STORE_ID ,SD.PRODUCT_DTL_ID , SD.PRODUCT_ID ) SD ON D.PRODUCT_DTL_ID = SD.PRODUCT_DTL_ID AND P.PRODUCT_ID = SD.PRODUCT_ID AND P.STORE_ID = SD.STORE_ID WHERE 1=1
AND P.STORE_ID = #{storeId}
AND C.CATEGORY_NM LIKE CONCAT('%', #{categoryNm}, '%')
AND P.PRODUCT_NM LIKE CONCAT('%', #{productNm}, '%')
AND D.RECEIVED_DATE >= #{receivedDateFrom}
AND D.RECEIVED_DATE <= #{receivedDateTo}
AND P.P_VARCODE_NO LIKE CONCAT('%', TRIM(#{pvarcodeNo}), '%')
AND P.STATUS = #{masterStatus}
GROUP BY P.PRODUCT_ID , P.STORE_ID , P.CATEGORY_ID , P.PARTNER_ID , P.PRODUCT_NM , P.P_PRODUCT_CD /* 계열사 상품 코드 88코드 */ , P.P_VARCODE_NO /* 계열사 상품 바코드 */ , P.STATUS , P.DESCRIPTION , C.CATEGORY_NM , S.PARTNER_NM HAVING 1=1
AND SUM(D.CUR_STOCK_QTY) > 0
AND NVL(SUM(D.CUR_STOCK_QTY),0) <= 0
ORDER BY P.PRODUCT_ID , P.CREATE_DATE DESC , (CASE WHEN MAX(D.RECEIVED_DATE) IS NULL THEN 0 ELSE 1 END) ASC , C.CATEGORY_NM , P.PRODUCT_NM ASC , LAST_RECEIVED_DATE DESC

/* 상품 검색 */ SELECT SPM.PARTNER_NM , LOC.LOCATION_NM , C.CATEGORY_NM , P.PRODUCT_NM , P.PRODUCT_ID , SUM(P.ORG_STOCK_QTY) ORG_STOCK_QTY , SUM(SD.SOLD_QTY) SOLD_QTY , ( SUM(P.ORG_STOCK_QTY) - IFNULL(SUM(SD.SOLD_QTY), 0) - IFNULL(SP.SPECIAL_QTY_UNSOLD, 0) ) AS CUR_STOCK_QTY -- , MIN(L.SALES_PRICE) AS SALES_PRICE , MAX(P.ORG_SALES_PRICE) AS ORG_SALES_PRICE , MAX(P.ORG_PRICE) AS ORG_PRICE -- , SUM(L.ORG_PRICE) AS ORG_PRICE , S.STORE_ID , SPM.PARTNER_ID FROM ( select a.PRODUCT_ID , a.PRODUCT_NM , b.LOCATION_ID , a.STORE_ID , a.CATEGORY_ID ,a.PARTNER_ID , sum(b.ORG_STOCK_QTY) ORG_STOCK_QTY , max(a.ORG_SALES_PRICE ) ORG_SALES_PRICE , max(a.ORG_PRICE ) ORG_PRICE , min(a.STATUS ) STATUS from product_mst a , product_dtl b where a.PRODUCT_ID = b.PRODUCT_ID and a.STATUS = 'ACTIVE' AND a.STORE_ID = #{storeId} AND b.LOCATION_ID = #{locationId} AND b.EXPIRATION_DATE >= CURDATE() group by a.PRODUCT_ID, a.PRODUCT_NM ,b.LOCATION_ID , a.STORE_ID , a.CATEGORY_ID ,a.PARTNER_ID ) P -- 🔹 실제 판매 수량 (DTL 기준) LEFT JOIN ( SELECT a.PRODUCT_ID, SUM(a.QTY) AS SOLD_QTY FROM sales_dtl a LEFT OUTER JOIN product_dtl b ON a.product_dtl_id = b.product_dtl_id WHERE b.EXPIRATION_DATE >= CURDATE() GROUP BY a.PRODUCT_ID ) SD ON P.PRODUCT_ID = SD.PRODUCT_ID -- 🔹 특가 등록 수량 LEFT JOIN ( /* 판매된 상품을 뺀 나머지 수량을 */ SELECT t.PRODUCT_ID , SUM(GREATEST(t.alloc_qty - IFNULL(t.sold_qty, 0), 0)) AS SPECIAL_QTY_UNSOLD FROM ( SELECT SD.PRODUCT_ID, SD.SPECIAL_DTL_ID, SD.QTY AS alloc_qty , SRV_SOLD.sold_qty FROM special_dtl SD JOIN special_mst M ON SD.SPECIAL_ID = M.SPECIAL_ID LEFT JOIN ( SELECT RD.SPECIAL_DTL_ID, SUM(RD.RESERVATION_CNT) AS sold_qty FROM special_rsv_dtl RD JOIN special_rsv_mst RM ON RD.SPECIAL_RSV_MST_ID = RM.SPECIAL_RSV_MST_ID WHERE 1=1
AND RM.SALES_ID IS NOT NULL AND RM.SALES_ID <> 0 -- ✅ 판매로 전환된 예약
GROUP BY RD.SPECIAL_DTL_ID ) SRV_SOLD ON SRV_SOLD.SPECIAL_DTL_ID = SD.SPECIAL_DTL_ID WHERE 1=1 AND (M.PROGRESS_TYPE = 'START' OR M.PROGRESS_TYPE = 'READY') ) t GROUP BY t.PRODUCT_ID ) SP ON P.PRODUCT_ID = SP.PRODUCT_ID LEFT JOIN store_mst S ON P.STORE_ID = S.STORE_ID LEFT JOIN category_mst C ON P.CATEGORY_ID = C.CATEGORY_ID LEFT JOIN store_location_mst LOC ON P.LOCATION_ID = LOC.LOCATION_ID LEFT JOIN store_partner_mst SPM ON P.STORE_ID = SPM.STORE_ID AND P.PARTNER_ID = SPM.PARTNER_ID WHERE 1=1
AND LOC.LOCATION_ID = #{locationId}
AND P.CATEGORY_ID = #{categoryId}
AND P.PRODUCT_NM LIKE CONCAT('%', #{productNm}, '%')
GROUP BY SPM.PARTNER_NM , LOC.LOCATION_NM , C.CATEGORY_NM , P.PRODUCT_NM , S.STORE_ID , P.PRODUCT_ID , SPM.PARTNER_ID HAVING CUR_STOCK_QTY > 0 ORDER BY P.PRODUCT_ID

	/* 상품 검색 v_product_stock로 전환 */
    SELECT *
    FROM   v_product_stock
	WHERE  1=1

	AND    STORE_ID = #{storeId}                /* 점포 격리: 특가 점포와 동일 점포 상품만 노출 */


	AND    LOCATION_ID = #{locationId}


	AND    CATEGORY_ID = #{categoryId}


	AND    PRODUCT_NM LIKE CONCAT('%', #{productNm}, '%')

	AND    CUR_STOCK_QTY > 0   
	ORDER BY PRODUCT_ID
